// §569 Alert Center + §387 Alert Thresholds.
// Collect upstream results and raise alerts for: Repository Failure,
// Workflow Failure, Provider Failure, High Cost, High Latency, Queue Backlog,
// Repository Health Drop, Low Benchmark Score. Thresholds are CONFIG-DRIVEN
// (config/admin.config.yaml -> alert_thresholds); NO hardcoded thresholds.
const cfg = $vars.CRIE_ALERT_THRESHOLDS ? JSON.parse($vars.CRIE_ALERT_THRESHOLDS) : {};
const items = $input.all().map(i => i.json);
const alerts = [];
function raise(type, severity, source, message, context){
  alerts.push({ alert_type: type, severity, source, message, context, correlation_id: $('Initialize').first().json.correlation_id });
}
// Repository health drop
const rh = items.find(x => x.repository_health !== undefined);
if (rh && cfg.repository_health_min !== undefined && Number(rh.repository_health) < cfg.repository_health_min) {
  raise('RepositoryHealthDrop', 'Warning', 'repository', 'Repository health below threshold', { observed: rh.repository_health, threshold: cfg.repository_health_min });
}
// High cost (daily)
const cost = items.find(x => x.daily_cost !== undefined);
if (cost && cfg.daily_cost_max !== undefined && Number(cost.daily_cost) > cfg.daily_cost_max) {
  raise('HighCost', 'Warning', 'cost', 'Daily cost above threshold', { observed: cost.daily_cost, threshold: cfg.daily_cost_max });
}
// Provider failure / breaker open
for (const x of items) {
  if (x.service && (x.status === 'Critical' || x.status === 'Offline' || x.breaker_state === 'Open')) {
    raise('ProviderFailure', x.status === 'Offline' ? 'Critical' : 'Warning', x.service, 'Provider unhealthy or breaker open', { status: x.status, breaker_state: x.breaker_state });
  }
}
return alerts.map(a => ({ json: a }));
